        out.t = t0 * A.t;
        out.n = c2V(-1.0f32, 0.0f32);
    } else if t1 >= t0 && t1 >= t2 && t1 >= t3 {
        out.t = t1 * A.t;
        out.n = c2V(1.0f32, 0.0f32);
    } else if t2 >= t0 && t2 >= t1 && t2 >= t3 {
        out.t = t2 * A.t;
        out.n = c2V(0.0f32, -1.0f32);
    } else {
        out.t = t3 * A.t;
        out.n = c2V(0.0f32, 1.0f32);
    }

